sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();

  var options = listChoices('urgency');
  return utils.ok(response, 200, { options: options });

  function listChoices(element) {
    var lang = (gs.getSession && gs.getSession().getLanguage) ? gs.getSession().getLanguage() : 'en';

    var urgencyRec = new GlideRecord('sys_choice');
    urgencyRec.addQuery('name', 'incident');
    urgencyRec.addQuery('element', element);
    // some instances store inactive as blank; include both
    var q = urgencyRec.addQuery('inactive', false);
    q.addOrCondition('inactive', '');
    urgencyRec.orderBy('sequence');
    urgencyRec.query();

    var byVal = {}; // value -> {value,label,sequence,_score}
    while (urgencyRec.next()) {
      var value = String(urgencyRec.value || '');
      if (!value) continue;

      var recLang = String(urgencyRec.language || '');
      var sequence = parseInt(String(urgencyRec.sequence || '9999'), 10);
      var label = String(urgencyRec.label || value);

      // prefer session language, then 'en', then blank
      var score = (recLang === lang) ? 3 : (recLang === 'en' ? 2 : (recLang === '' ? 1 : 0));
      var prev = byVal[value];
      if (!prev || score > prev._score) {
        byVal[value] = { value: value, label: label, sequence: sequence, _score: score };
      }
    }

    var out = [];
    for (var k in byVal) out.push(byVal[k]);
    if (!out.length) {
      // safe fallback (OOB defaults)
      out = [
        { value: '1', label: '1 - High',   sequence: 10 },
        { value: '2', label: '2 - Medium', sequence: 20 },
        { value: '3', label: '3 - Low',    sequence: 30 }
      ];
    }

    out.sort(function(a, b) {
      if (a.sequence !== b.sequence) return a.sequence - b.sequence;
      if (a.value === b.value) return 0;
      return a.value < b.value ? -1 : 1;
    });

    // strip sequence/_score for response
    return out.map(function(o) { return { value: o.value, label: o.label }; });
  }
})(request, response);
